import { Level, LogData, TransportOptions } from '../typings';
/**
 * Transport is an output channel of the log that can be output to a file, stdout/stderr or network.
 * A logger can configure multiple Transports to meet a variety of complex needs
 */
export default abstract class Transport {
    readonly name: string;
    level: Level | undefined;
    enabled: boolean;
    constructor(options?: TransportOptions);
    setLevel(level: Level): void;
    getLevel(): Level | undefined;
    /**
     * enable transport
     */
    enable(): void;
    /**
     * disable transport
     */
    disable(): void;
    /**
     * should output log or not
     */
    shouldLog(level: Level): boolean;
    /**
     * log data
     * @param formattedData data transformed by generic formatter
     * @param data transformed data
     */
    abstract log(formattedData: string, data?: LogData): void;
    /**
     * Asynchronously flush logs to file, stdout/stderr, and network.
     */
    abstract flush(): void;
    /**
     * Synchronously flush logs to file, stdout/stderr, and network.
     */
    abstract flushSync(): void;
    /**
     * will close the exists write stream and create a new one.
     */
    abstract reload(): void;
    /**
     * close Transport.
     */
    abstract close(): void;
}
